local xml = require "lxp.lxp"

-- Function to parse XML and extract data
local function parse_xml(xml_data)
    local result = {}
    local parser = xml.new("start", 
        function(tag, attr)
            if tag == "data" then
                table.insert(result, {name = attr.name, value = ""})
            end
        end,
        function(tag, text)
            for i, v in ipairs(result) do
                if v.name == tag then
                    v.value = text
                end
            end
        end,
        "end",
        function(tag)
            -- No action needed on end tags
        end
    )
    
    parser:parse(xml_data)
    return result
end

-- OpenResty handler
local function soap_handler()
    local xml_data = ngx.req.get_body_data()
    if not xml_data then
        ngx.status = 400
        ngx.say("No XML data provided")
        return
    end
    
    -- Parse the XML data
    local data = parse_xml(xml_data)
    
    -- Process the extracted data
    for _, v in ipairs(data) do
        if v.name == "name" then
            ngx.say("Name: ", v.value)
        elseif v.name == "value" then
            ngx.say("Value: ", v.value)
        end
    end
end

